**Gaps:** `isBook` validation edge cases (only exercised indirectly through the module-level `books` array), `getBook`/`booksInCategory`/`categoryOf` unknown-id paths, `hasChapterFile` boundaries, `loadChapter`'s markdown-contract parsing (missing sections, case-insensitive headings, missing title fallback), `bookStats`' division-by-zero when `originalPages === 0`, `fmtDuration` boundaries, `searchBooks` scoring/ordering.

```ts
// src/lib/content.test.ts
import { describe, it, expect, vi } from 'vitest'

describe('countWords', () => {
  it('returns 0 for empty/whitespace-only strings', () => {
    expect(countWords('')).toBe(0)
    expect(countWords('   \n\t ')).toBe(0)
  })
  it('collapses multiple whitespace runs', () => {
    expect(countWords('a  b\n\nc')).toBe(3)
  })
})

describe('getBook / booksInCategory / categoryOf', () => {
  it('getBook returns undefined for unknown or undefined id', () => {
    expect(getBook('nope')).toBeUndefined()
    expect(getBook(undefined)).toBeUndefined()
  })
  it('booksInCategory returns [] for a category with no books', () => {
    expect(booksInCategory('nonexistent-category')).toEqual([])
  })
  it('categoryOf returns undefined when categoryId has no matching category', () => {
    const book = { ...someBook, categoryId: 'ghost' }
    expect(categoryOf(book)).toBeUndefined()
  })
})

describe('hasChapterFile', () => {
  it('returns false for unknown book id, unknown chapter number, and n=0', () => {
    expect(hasChapterFile('unknown-book', 1)).toBe(false)
    expect(hasChapterFile(realBookId, 999)).toBe(false)
    expect(hasChapterFile(realBookId, 0)).toBe(false)
  })
})

describe('loadChapter', () => {
  it('returns null when the chapter file does not exist', async () => {
    expect(await loadChapter('unknown', 1)).toBeNull()
  })
  it('falls back to "Chapter N" title when no "# Title" heading is present', async () => {
    // requires a fixture chapter without a leading H1
  })
  it('degrades gracefully when Key Ideas / In Practice sections are missing', async () => {
    // body should absorb all content; keyIdeas/inPractice stay []
  })
  it('matches "Key Ideas"/"In Practice" headings case-insensitively and with trailing text', async () => {
    // e.g. "## key ideas" and "## Key Ideas & Frameworks" both match via startsWith
  })
  it('extracts only "-"/"*" bullet lines, ignoring prose lines in the same block', async () => {})
})

describe('bookStats', () => {
  it('does not throw and clamps savedPct when originalPages is 0 (div-by-zero)', () => {
    const b = { ...someBook, originalPages: 0 }
    const stats = bookStats(b)
    expect(Number.isFinite(stats.savedPct)).toBe(true)
  })
  it('defaults a chapter with no "minutes" field to 9', () => {
    const b = { ...someBook, map: { ...someBook.map, chapters: [{ number: 1, title: 't', summary: 's', minutes: undefined, readIf: [] }] } }
    expect(bookStats(b).deepMinutes).toBe(9)
  })
})

describe('fmtDuration', () => {
  it.each([
    [0, '0 min'], [59, '59 min'], [60, '1 h'], [90, '1 h 30 m'], [125, '2 h 5 m'],
  ])('formats %i minutes as %s', (mins, expected) => {
    expect(fmtDuration(mins)).toBe(expected)
  })
})

describe('searchBooks', () => {
  it('returns all books for an empty/whitespace query', () => {
    expect(searchBooks('   ')).toEqual(books)
  })
  it('returns [] when no term matches title/author/tagline/chapter titles', () => {
    expect(searchBooks('zzzznomatch')).toEqual([])
  })
  it('ranks title/author matches above chapter-title-only matches', () => {
    // book A matches in title (score 5), book B only in a chapter title (score 1)
    // expect A before B
  })
  it('is case-insensitive', () => {
    expect(searchBooks('ALCHEMIST').length).toBeGreaterThan(0)
  })
})
```

