**Gaps:** no test of `mdToHtml` vs `mdInline` (block wrapping vs inline-only), GFM features (tables/strikethrough), and — notably — **no test documenting that `marked` output is not sanitized** before `dangerouslySetInnerHTML` is used in `Markdown`, `Reader`, and `BookMap`. Since all content is first-party, this may be intentional, but there's no regression guard if untrusted input (e.g. future user-generated notes) is ever piped through.

```ts
// src/lib/markdown.test.tsx
import { render } from '@testing-library/react'
import { describe, it, expect } from 'vitest'
import { mdToHtml, mdInline, Markdown } from './markdown'

describe('mdToHtml', () => {
  it('wraps a plain sentence in <p>', () => {
    expect(mdToHtml('hello')).toContain('<p>hello</p>')
  })
  it('renders GFM tables and strikethrough', () => {
    expect(mdToHtml('~~gone~~')).toContain('<del>gone</del>')
  })
})

describe('mdInline', () => {
  it('does not wrap output in a block element', () => {
    expect(mdInline('**bold**')).not.toMatch(/^<p>/)
    expect(mdInline('**bold**')).toContain('<strong>bold</strong>')
  })
})

describe('Markdown component', () => {
  it('renders parsed HTML and applies className', () => {
    const { container } = render(<Markdown text="**hi**" className="extra" />)
    expect(container.querySelector('.md.extra strong')).toBeTruthy()
  })
})
```

