```ts
// src/lib/prefs.test.ts
describe('resolveReaderTheme', () => {
  it('follows appTheme when readerTheme is null', () => {
    expect(resolveReaderTheme({ ...base, readerTheme: null, appTheme: 'dark' })).toBe('dark')
    expect(resolveReaderTheme({ ...base, readerTheme: null, appTheme: 'light' })).toBe('paper')
