describe('bumpFontScale', () => {
  it('clamps to [0.85, 1.3]', () => {
    updatePrefs({ fontScale: 1.3 })
    bumpFontScale(0.5)
    expect(getPrefs().fontScale).toBe(1.3)
    updatePrefs({ fontScale: 0.85 })
    bumpFontScale(-0.5)
    expect(getPrefs().fontScale).toBe(0.85)
  })
  it('avoids floating point drift across repeated small bumps', () => {
    updatePrefs({ fontScale: 1 })
    for (let i = 0; i < 5; i++) bumpFontScale(0.05)
    expect(getPrefs().fontScale).toBe(1.25) // not 1.2500000000000002
  })
})

describe('updatePrefs', () => {
  it('merges a partial patch without clobbering other fields', () => {
    updatePrefs({ wide: true })
    expect(getPrefs().fontScale).toBe(1) // unaffected
  })
})
