**Gaps:** `sanitize` is unexported but load-bearing — every public function routes through it and it's the sole defense against corrupted `localStorage`. No test exercises malformed input. `completionPct`'s stale-chapter-numbers guard (`Math.min(read, totalChapters)`) is untested. `latestProgress` tie-breaking and empty-state are untested.

```ts
// src/lib/progress.test.ts
describe('sanitize (via public API)', () => {
  it('useBookProgress returns EMPTY_PROGRESS for a book with no stored entry', () => {
    expect(useBookProgressValue('never-touched')).toEqual(EMPTY_PROGRESS)
  })
  it('recovers from corrupted stored shape (non-array chaptersRead, non-number lastChapter)', () => {
    localStorage.setItem('distill.progress.v1', JSON.stringify({ b: { chaptersRead: 'oops', lastChapter: 'x', mapRead: 1 } }))
    // reload store, read progress for 'b'
    // expect chaptersRead === [], lastChapter === undefined, mapRead === false
  })
  it('dedupes and sorts chaptersRead', () => {
    localStorage.setItem('distill.progress.v1', JSON.stringify({ b: { chaptersRead: [3, 1, 1, 2] } }))
    // expect [1, 2, 3]
  })
})

describe('markChapterRead / toggleChapterRead', () => {
  it('markChapterRead does not duplicate an already-read chapter', () => {
    markChapterRead('b', 1); markChapterRead('b', 1)
    expect(useBookProgressValue('b').chaptersRead).toEqual([1])
  })
  it('toggleChapterRead flips membership without touching lastChapter', () => {
    setLastChapter('b', 5)
    toggleChapterRead('b', 2)
    expect(useBookProgressValue('b').lastChapter).toBe(5)
  })
