describe('completionPct', () => {
  it('ignores chaptersRead entries beyond totalChapters (stale data)', () => {
    const p = { mapRead: true, chaptersRead: [1, 2, 99], updatedAt: 1 }
    expect(completionPct(2, p)).toBe(100) // not > 100
  })
