describe('latestProgress', () => {
  it('returns null when state is empty or all updatedAt are 0', () => {
    expect(latestProgress({})).toBeNull()
    expect(latestProgress({ a: { ...EMPTY_PROGRESS, updatedAt: 0 } })).toBeNull()
  })
  it('picks the entry with the highest updatedAt', () => {
    const state = { a: { ...EMPTY_PROGRESS, updatedAt: 10 }, b: { ...EMPTY_PROGRESS, updatedAt: 20 } }
    expect(latestProgress(state)?.bookId).toBe('b')
