**Gaps:** localStorage-quota/private-mode failure path (`try/catch` around `setItem`), corrupted-JSON recovery, listener subscribe/unsubscribe semantics, merge-of-fallback-with-partial-stored-object (important for schema migrations — new `Prefs` fields added later must get their default even for existing users).

```ts
// src/lib/store.test.ts
describe('createLocalStore', () => {
  it('merges stored JSON over fallback so new fields get defaults', () => {
    localStorage.setItem('k', JSON.stringify({ existingField: 'x' }))
    const store = createLocalStore('k', { existingField: 'y', newField: 42 })
    expect(store.get()).toEqual({ existingField: 'x', newField: 42 })
  })
  it('falls back to defaults when stored JSON is corrupted', () => {
    localStorage.setItem('k2', '{not json')
    const store = createLocalStore('k2', { a: 1 })
    expect(store.get()).toEqual({ a: 1 })
  })
  it('keeps in-memory state when localStorage.setItem throws (private mode/quota)', () => {
    const store = createLocalStore('k3', { a: 1 })
    vi.spyOn(Storage.prototype, 'setItem').mockImplementation(() => { throw new Error('quota') })
    expect(() => store.set({ a: 2 })).not.toThrow()
    expect(store.get()).toEqual({ a: 2 })
  })
  it('notifies subscribers on set, and stops after unsubscribe', () => {
    const store = createLocalStore('k4', { a: 1 })
    const fn = vi.fn()
    const unsub = store.subscribe(fn)
    store.set({ a: 2 })
    unsub()
    store.set({ a: 3 })
    expect(fn).toHaveBeenCalledTimes(1)
  })
})
```

