This module has real bugs waiting to be caught by tests. It needs a `speechSynthesis`/`SpeechSynthesisUtterance` mock since jsdom doesn't implement the Web Speech API.

```ts
// src/test/mockSpeechSynthesis.ts
export function installSpeechSynthesisMock() {
  const utterances: any[] = []
  const mock = {
    speak: vi.fn((u: any) => { utterances.push(u); /* test controls u.onend/.onerror manually */ }),
    cancel: vi.fn(),
    pause: vi.fn(),
    resume: vi.fn(),
    getVoices: vi.fn(() => []),
    addEventListener: vi.fn(),
  }
  vi.stubGlobal('speechSynthesis', mock)
  vi.stubGlobal('SpeechSynthesisUtterance', vi.fn((text) => ({ text })))
  return { mock, utterances }
}
```

